import matplotlib.pyplot as plt
import numpy as np
from collections import Counter
import os
from torchvision import datasets, transforms

def plot_class_distribution_comparison(data_dir, al_selected_idx_list, random_selected_idx_list, 
                                     save_path=None, figsize=(12, 8)):
    """
    繪製類別分佈比較圖，支援多組數據並計算平均值和標準差，顯示絕對數量
    
    參數:
        data_dir: 數據集目錄路徑
        al_selected_idx_list: AL 選中的樣本索引列表的列表 [[run1_idx], [run2_idx], ...]
        random_selected_idx_list: Random 選中的樣本索引列表的列表 [[run1_idx], [run2_idx], ...]
        save_path: 保存圖片的路徑 (可選)
        figsize: 圖片大小
    """
    
    # 如果輸入是單一列表，轉換為列表的列表
    if isinstance(al_selected_idx_list[0], int):
        al_selected_idx_list = [al_selected_idx_list]
    if isinstance(random_selected_idx_list[0], int):
        random_selected_idx_list = [random_selected_idx_list]
    
    # 建立數據集
    transform = transforms.Compose([
        transforms.ToTensor(),
        transforms.Normalize([0.5, 0.5, 0.5], [0.5, 0.5, 0.5])
    ])
    full_dataset = datasets.ImageFolder(os.path.join(data_dir, 'train'), transform=transform)
    class_names = full_dataset.classes
    
    # 定義顯示順序
    display_order = ['Normal', 'Eczema', 'Solar lentigo', 'Nevus', 'Psoriasis', 'Seborrhoeic keratosis', 'Vitiligo']
    
    # 建立原始類別名稱到索引的映射
    class_to_idx = {name: idx for idx, name in enumerate(class_names)}
    
    # 建立顯示標籤（將 Seborrhoeic keratosis 縮寫為 SK）
    display_labels = []
    ordered_class_indices = []
    
    for display_name in display_order:
        if display_name == 'Seborrhoeic keratosis':
            display_labels.append('SK')
            if display_name in class_to_idx:
                ordered_class_indices.append(class_to_idx[display_name])
        else:
            display_labels.append(display_name)
            if display_name in class_to_idx:
                ordered_class_indices.append(class_to_idx[display_name])
    
    # 計算多組實驗的絕對數量
    al_counts_all_runs = []
    random_counts_all_runs = []
    
    # 處理每組實驗
    for run_idx in range(len(al_selected_idx_list)):
        al_selected_idx = al_selected_idx_list[run_idx]
        random_selected_idx = random_selected_idx_list[run_idx]
        
        # 獲取選中樣本的標籤
        al_labels = [full_dataset.targets[idx] for idx in al_selected_idx]
        random_labels = [full_dataset.targets[idx] for idx in random_selected_idx]
        
        # 統計每個類別的數量
        al_counts = Counter(al_labels)
        random_counts = Counter(random_labels)
        
        # 計算絕對數量 (按照指定順序)
        al_counts_ordered = [al_counts.get(class_idx, 0) for class_idx in ordered_class_indices]
        random_counts_ordered = [random_counts.get(class_idx, 0) for class_idx in ordered_class_indices]
        
        al_counts_all_runs.append(al_counts_ordered)
        random_counts_all_runs.append(random_counts_ordered)
    
    # 計算平均值和標準差
    al_counts_all_runs = np.array(al_counts_all_runs)
    random_counts_all_runs = np.array(random_counts_all_runs)
    
    al_mean = np.mean(al_counts_all_runs, axis=0)
    al_std = np.std(al_counts_all_runs, axis=0)
    random_mean = np.mean(random_counts_all_runs, axis=0)
    random_std = np.std(random_counts_all_runs, axis=0)
    
    # 設置圖形
    fig, ax = plt.subplots(figsize=figsize)
    
    # 設置 x 軸位置
    x = np.arange(len(display_labels))
    width = 0.35  # 柱狀圖寬度
    
    # 繪製柱狀圖 (帶有誤差棒)
    bars1 = ax.bar(x - width/2, random_mean, width, yerr=random_std, 
                   label='Random Sampling', 
                   color='lightblue', alpha=0.8, edgecolor='navy', linewidth=1,
                   capsize=5, error_kw={'linewidth': 1.5, 'markeredgewidth': 1.5})
    bars2 = ax.bar(x + width/2, al_mean, width, yerr=al_std,
                   label='Active Learning (Margin)', 
                   color='lightcoral', alpha=0.8, edgecolor='darkred', linewidth=1,
                   capsize=5, error_kw={'linewidth': 1.5, 'markeredgewidth': 1.5})
    
    ax.set_ylabel('Number of Selected Samples', fontsize=20)
    ax.set_xticks(x)
    ax.set_xticklabels(display_labels, rotation=45, ha='right', fontsize=18)
    ax.tick_params(axis='y', labelsize=18)
    ax.legend(fontsize=20)
    
    # 添加網格
    ax.grid(True, alpha=0.3, linestyle='--')
    ax.set_axisbelow(True)
    
    # 移除數值標籤函數呼叫
    # add_value_labels(bars1, random_mean, random_std)
    # add_value_labels(bars2, al_mean, al_std)
    
    # 調整佈局
    plt.tight_layout()
    
    # 保存圖片
    if save_path:
        plt.savefig(save_path, dpi=300, bbox_inches='tight')
        print(f"圖片已保存至: {save_path}")
    
    plt.show()
    
    # 打印數值比較
    print("\n" + "="*80)
    print("DETAILED COUNT COMPARISON")
    print("="*80)
    if len(al_selected_idx_list) > 1:
        print(f"{'Class Name':<15} {'Random Mean':<12} {'Random Std':<12} {'AL Mean':<12} {'AL Std':<12} {'Diff Mean':<12}")
    else:
        print(f"{'Class Name':<15} {'Random Count':<12} {'AL Count':<12} {'Difference':<12}")
    print("-"*80)
    
    for i, display_label in enumerate(display_labels):
        if len(al_selected_idx_list) > 1:
            diff_mean = al_mean[i] - random_mean[i]
            symbol = "📈" if diff_mean > 0 else "📉" if diff_mean < 0 else "➡️"
            print(f"{display_label:<15} {random_mean[i]:<12.1f} {random_std[i]:<12.1f} {al_mean[i]:<12.1f} {al_std[i]:<12.1f} {symbol} {diff_mean:+.1f}")
        else:
            diff = al_mean[i] - random_mean[i]
            symbol = "📈" if diff > 0 else "📉" if diff < 0 else "➡️"
            print(f"{display_label:<15} {random_mean[i]:<12.0f} {al_mean[i]:<12.0f} {symbol} {diff:+.0f}")
    
    print("="*80)
    
    # 返回統計結果
    return {
        'al_mean': al_mean,
        'al_std': al_std,
        'random_mean': random_mean,
        'random_std': random_std,
        'display_labels': display_labels
    }



